var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<b>MAS-03</b>: 구 멘도사, 외각진입로 - <b>14:05:38</b>       \\n<color=#ffd34c>R7 비정규 정찰대</color>, 핀리 마이닝 인더스트리       \\nCSE Lv. <b>2</b>       ","JPN":"<b>MAS-03</b>：旧メンドーサ、郊外進入路 - <b>14:05:38</b>       \\n<color=#ffd34c>R7 非正規偵察隊</color>、フィンリー・マイニングインダストリー       \\nCSE Lv. <b>2</b>       ","ENG":"<b>MAS-03</b>: Old Mendoza, Perimeter Access - <b>14:05:38</b>       \\n<color=#ffd34c>R7 Irregular Scouts</color>, Finley Mining Industries       \\nCSE Lv. <b>2</b>       ","TWN":"<b>MAS-03</b>：舊門多薩，外角進路-<b>14:05:38</b> \\n\\n<color=#ffd34c>R7 非正規偵察隊</color>，芬利礦業\\nCSE Lv. <b>2</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"네, 네. 현재 목표지점으로 이동 중.","JPN":"はい、はい。現在、目標地点へ移動中。","ENG":"Copy. Approaching objective.","TWN":"是，是，我們現在正在前往目的地。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"대략 오 분 뒤, 십육 시 정각에 도착할 예정입니다.","JPN":"およそ5分後、16時ちょうどに到着する予定です。","ENG":"ETA, 16:00 sharp. We’ll be there in about 5 minutes.","TWN":"大約五分鐘後，我們將在十六時準時到達。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"도착해서 대기 중인 카운터와 접선하면 다시 연락드리겠습니다.","JPN":"待機中のカウンターと合流後、また連絡します。","ENG":"We’ll get in touch once we make contact with the Counter on standby.","TWN":"到達目的地和制裁者會合後，我們將再次與您聯繫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐래?","JPN":"何だって？","ENG":"What did they say?","TWN":"他說什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"위험지대니까 카운터 만날 때까지 주의하라는 거지, 뭐. ","JPN":"危険地帯だからカウンターに会うまで気をつけろ、だそうよ。","ENG":"You know, the usual. Stay on our toes till we meet the Counter since this is a danger zone. ","TWN":"說那裡很危險，在見到制裁者之前要多加小心。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......장갑차 새로 산 거니까 조심하고.","JPN":"……あと、装甲車は新品だから要注意とも。","ENG":"And to be careful with the new APC.","TWN":"……因為這是新買的裝甲車，所以要我們小心一點。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"우리 말고 차 조심하라는 거지?","JPN":"俺たちより装甲車の方が大事なのか？","ENG":"They just don’t want their new ride ruined, huh? Couldn’t care less about us.","TWN":"他關心車卻不關心我們？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"거 참 눈물 나게 고맙네.","JPN":"は、ありがてえな。","ENG":"Jeez, I appreciate their \\"concern.\\"","TWN":"我感動得都要流眼淚了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"정말이지, 이 덜컹거리는 차는 몇 주를 타도 적응이 안 된단 말이야.","JPN":"こいつはいくら乗っても慣れねえんだよ。","ENG":"Seriously, this I could never get used to riding in this clunky thing.","TWN":"說真的，這輛車嘎嘎作響的，坐幾個星期都不適應。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이딴 거 걱정할 거면 사원 복지에나 신경 좀 써 주지.","JPN":"こんな車の心配をするくらいなら、社員の福利厚生にもっと気を使えってんだ。","ENG":"They should've given us a raise instead of buying this piece of crap.","TWN":"如果他真擔心這件事的話，那就在員工的福利上多花點心思吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐 별 수 있나? 이쪽 동네에서 도로정비 같은 걸 기대할 수도 없잖아.","JPN":"仕方ないじゃない。この辺りの道路は整備なんて期待できないし。","ENG":"Oh well. It’s not like this part of the neighborhood is known for its perfectly paved roads.","TWN":"那你要怎樣？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"덜컹거려서 싫으면 걸어 다니시든지?","JPN":"そんなに嫌なら歩いたらどう？","ENG":"If you hate the bumpy ride so much, why don't you just walk?","TWN":"你嫌它吵是不會自己走喔？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"야야. 아무리 그래도 이 동네에서 걸어 다니는 건 좀 아니지.","JPN":"おいおい。いくら何でも、この辺りを歩くのは無理があるだろ。","ENG":"Come on. I'd be crazy to go around on foot in this neighborhood.","TWN":"不管怎麼說，在這裡都不能用走的吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"나도 이런 게 마음에 들진 않지만 말이야. ","JPN":"私も別に、こいつが気に入ってるわけではないけど。","ENG":"I’m not saying I like this any better than you do. ","TWN":"其實，我也不怎麼滿意。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"투정은 부리지 말자고. 차가 있는 것만 해도 감지덕지해야지.","JPN":"わがままは言ってられないわ。車があるだけでも感謝しなきゃ。","ENG":"But let’s stop complaining. We should be thankful we at least have a car.","TWN":"但還是別抱怨吧。能有輛車就要心存感激了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"안 그래? 베테랑씨?","JPN":"そう思わない？ベテランさん？","ENG":"Isn’t that right? Mr. Veteran?","TWN":"不是嗎？ 老手先生？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"매우 동감이다. 여긴 그나마 차라도 있지.......","JPN":"同感だ。ここは車があるだけマシだ……","ENG":"Agreed. At least we have a car here...","TWN":"我十分認同妳的話，至少我們還有輛車……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"에이, 설마. 차도 없이 임무에 집어넣는다고?","JPN":"おい、まさか。車すらないとこがあるなんて言うなよ？","ENG":"Oh, come on! They seriously make you go on missions without a vehicle?","TWN":"等等，真的假的，他們不會要我們連車都沒有就執行任務吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아무리 요즘 블랙기업이 많다고 해도 그건 좀 과장이 심한데.","JPN":"最近ブラック企業が増えたのは確かだが、いくら何でもそれはひどすぎんだろ。","ENG":"I mean I get that there's a lot of cheap companies out there, but that’s a stretch even by their standards.","TWN":"就算最近黑心企業不少，但這也太誇張了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭘 모르는군. 요즘 기업들 모토는 <color=#ffd34c>유류비보다 싼 인건비</color>라고.","JPN":"まだ知らないようだな、昨今の企業のモットーは<color=#ffd34c>ガソリン代より安い人件費</color>だ。","ENG":"You have no idea. The mantra in the business these days is <color=#ffd34c>cheaper wages than fuel prices</color>.","TWN":"你真是什麼都不知道啊。最近企業的座右銘可是<color=#ffd34c>人事費比燃料費便宜</color>呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"히야...... 진짜 지독하게 빨아먹는구만. 깎을 게 없어서 용병 월급을 깎냐?","JPN":"はあ……ブラックすぎるわね。傭兵の給料をケチるなんて。","ENG":"Wow... They’re really trying to rip us off, aren’t they? They’re cutting corners on mercenary pay of all things?","TWN":"我的天……這也太爛了吧。沒東西可以剝削，就只好扣傭兵的工資了？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......시장 논리로 돌아간다는 거지.","JPN":"……この業界はそうやって回ってるんだ。","ENG":"It’s all about leaving it to the market forces.","TWN":"……就是說要回歸市場邏輯。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그리고 나같이 그런 회사에서 일할 수밖에 없는 인간도 있는 법이고.","JPN":"それに俺みたいに、そういう企業でしか働けない人間もいる。","ENG":"Besides, guys like me don’t have much of a choice but to work for such miserly companies.","TWN":"像我這樣只能在這種公司工作的人也不少。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그렇게 아껴서 뭘 어디에 쓴대?","JPN":"そんなにケチってどうするんだ？","ENG":"What do they even do with all the money they save?","TWN":"這樣省下來的錢，到底要花在什麼地方啊？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"인건비 깎아서 남기면 순수익이잖아. 이것도 다 장산데, 돈 남기려고 하는 거 아니겠어?","JPN":"これも商売なんだ、金を稼ぐためだろ。人件費を削ると利益になるからな。","ENG":"Less wages means more profit for the company. After all, this is business. It’s all about making more money.","TWN":"人事費降低後剩下的不就是純收益嗎？這都是生意，不就是想多賺點錢嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 이해 안 가는 것도 아니지만.","JPN":"まあ、わからなくもない。","ENG":"I mean, I guess it makes sense from their angle.","TWN":"嗯……雖然也不是不能理解。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"카운터 놈들은 돈에서 헤엄칠 정도로 번다던데, 같이 목숨 거는 우리는 이게 다 뭐야?","JPN":"カウンターはバカみたいに稼いでるんだろ？それじゃあ、一緒に命懸けで戦ってる俺たちは何なんだ。","ENG":"Counters are practically swimming in gold for doing the same crap as us... and this is all we get for busting our ass?","TWN":"制裁者賺的錢多到都可以用來游泳了，和他們一起拚命的我們又算什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"어쩔 수 없잖아? 우린 대체 가능한데 카운터는 대체 불가능하니까.","JPN":"仕方ないわよ。私たちは替えが利くけど、カウンターはそうはいかないもの。","ENG":"Meh, it is what it is. We're replaceable, but Counters aren’t.","TWN":"沒辦法。因為我們可有可無，但制裁者卻不可取代呀。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그것도 제대로 된 회사에 소속된 카운터 이야기지.","JPN":"……ちゃんとした企業に所属してるカウンターはそうだ。","ENG":"And that’s only for Counters that manage to score cushy contract with major companies.","TWN":"……而且那說的也是正規公司的制裁者。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"실제로는 우리처럼 부평초 신세인 놈들도 많아.","JPN":"だが、実際には俺たちと大差ないやつらも多い。","ENG":"Most of them are just as screwed as we are.","TWN":"實際上，像我們這樣居無定所的傢伙們也不少。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어딘가에는 노숙하는 카운터도 있다던데?","JPN":"噂では、野宿してるカウンターもいるらしいからな。","ENG":"I heard there are even homeless Counters out there.","TWN":"聽說有些地方也有露宿街頭的制裁者？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐야, 그게? 그런 게 있을 리가 없잖아?","JPN":"はあ、何だそれ？そんなわけないだろ？","ENG":"Seriously? That can’t be true.","TWN":"什麼？真的假的？不可能吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아, 그건 나도 들어 본 적 있어.","JPN":"あ、それ、私も聞いたことある。","ENG":"Oh, I’ve heard of that too.","TWN":"這我也聽說過。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"진짜냐?","JPN":"本当か？","ENG":"For real?","TWN":"真的嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"돈 많은 놈이 왜 노숙을 해? 카운터는 다 변태냐?","JPN":"金があるのになんで野宿なんかするんだ？　変なやつらだな。","ENG":"Why would they stay homeless when they're raking in all that dough? These Counters are messed up in the head.","TWN":"有那麼多錢還露宿街頭？他們腦子壞掉了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"ちょっとまった。","ENG":"Hang on.","TWN":"等一下！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"조용히.","JPN":"静かに。","ENG":"Quiet.","TWN":"安靜！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"무, 무슨 일이야?","JPN":"な、なんだ？","ENG":"W-what's going on?","TWN":"怎麼回事？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"무기를 들어.","JPN":"武器を構えろ。","ENG":"Get your weapons ready.","TWN":"拿起武器。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"저쪽에서 무슨 소리가 들려.","JPN":"向こうから音が聞こえる。","ENG":"I hear something from over there.","TWN":"那邊有什麼聲音。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};